// ---- Testing in Android — Unit Tests ----
// Dependencies:
// testImplementation("junit:junit:4.13.2")
// testImplementation("org.jetbrains.kotlinx:kotlinx-coroutines-test:1.7.3")
// testImplementation("androidx.arch.core:core-testing:2.2.0")

// ---- Domain layer tests ----

// ---- Entity tests ----
data class Player(val id: Int, val name: String, val health: Int)

class PlayerTest {
    @Test
    fun `test player creation`() {
        val player = Player(1, "Hero", 100)
        assertThat(player.id).isEqualTo(1)
        assertThat(player.name).isEqualTo("Hero")
        assertThat(player.health).isEqualTo(100)
    }

    @Test
    fun `test player data class`() {
        val player1 = Player(1, "Hero", 100)
        val player2 = player1.copy(name = "Aragorn")

        assertThat(player1.name).isNotEqualTo(player2.name)
        assertThat(player1.id).isEqualTo(player2.id)
    }
}

// ---- Use Case tests ----
class GetPlayersUseCaseTest {
    private lateinit var repository: PlayerRepository
    private lateinit var getPlayers: GetPlayersUseCase

    @Before
    fun setup() {
        repository = mockk()
        getPlayers = GetPlayersUseCase(repository)
    }

    @Test
    fun `test get players success`() = runTest {
        val expectedPlayers = listOf(
            Player(1, "Hero", 100),
            Player(2, "Aragorn", 120)
        )
        coEvery { repository.getPlayers() } returns expectedPlayers

        val result = getPlayers()

        assertThat(result).isEqualTo(expectedPlayers)
        coVerify { repository.getPlayers() }
    }

    @Test
    fun `test get players error`() = runTest {
        val error = Exception("Network error")
        coEvery { repository.getPlayers() } throws error

        val exception = shouldThrow<Exception> {
            runBlocking { getPlayers() }
        }

        assertThat(exception.message).isEqualTo("Network error")
    }
}

class SavePlayerUseCaseTest {
    private lateinit var repository: PlayerRepository
    private lateinit var savePlayer: SavePlayerUseCase

    @Before
    fun setup() {
        repository = mockk()
        savePlayer = SavePlayerUseCase(repository)
    }

    @Test
    fun `test save player success`() = runTest {
        val player = Player(1, "Hero", 100)
        coEvery { repository.savePlayer(player) } returns Unit

        savePlayer(player)

        coVerify { repository.savePlayer(player) }
    }
}

// ---- ViewModel tests ----
@OptIn(ExperimentalCoroutinesApi::class)
class PlayerViewModelTest {
    private lateinit var viewModel: PlayerViewModel
    private lateinit var getPlayers: GetPlayersUseCase
    private lateinit var savePlayer: SavePlayerUseCase
    private lateinit var deletePlayer: DeletePlayerUseCase

    @Before
    fun setup() {
        getPlayers = mockk()
        savePlayer = mockk()
        deletePlayer = mockk()

        viewModel = PlayerViewModel(
            getPlayers,
            savePlayer,
            deletePlayer
        )
    }

    @Test
    fun `test load players success`() = runTest {
        val players = listOf(
            Player(1, "Hero", 100),
            Player(2, "Aragorn", 120)
        )
        coEvery { getPlayers() } returns players

        viewModel.loadPlayers()

        val state = viewModel.uiState.value
        assertThat(state.isLoading).isFalse()
        assertThat(state.players).isEqualTo(players)
        assertThat(state.error).isNull()
    }

    @Test
    fun `test load players error`() = runTest {
        val error = Exception("Network error")
        coEvery { getPlayers() } throws error

        viewModel.loadPlayers()

        val state = viewModel.uiState.value
        assertThat(state.isLoading).isFalse()
        assertThat(state.players).isEmpty()
        assertThat(state.error).isEqualTo("Network error")
    }

    @Test
    fun `test save player`() = runTest {
        val player = Player(0, "Hero", 100)
        coEvery { savePlayer(player) } returns Unit
        coEvery { getPlayers() } returns listOf(player)

        viewModel.savePlayer(player)

        val state = viewModel.uiState.value
        assertThat(state.players).contains(player)
    }
}

// ---- Repository tests ----
class PlayerRepositoryImplTest {
    private lateinit var repository: PlayerRepositoryImpl
    private lateinit var localDataSource: LocalDataSource
    private lateinit var remoteDataSource: RemoteDataSource

    @Before
    fun setup() {
        localDataSource = mockk()
        remoteDataSource = mockk()
        repository = PlayerRepositoryImpl(localDataSource, remoteDataSource)
    }

    @Test
    fun `test get players from remote when cache empty`() = runTest {
        val remotePlayers = listOf(
            Player(1, "Hero", 100)
        )
        coEvery { remoteDataSource.getPlayers() } returns remotePlayers
        coEvery { localDataSource.savePlayers(remotePlayers) } returns Unit
        coEvery { localDataSource.getPlayers() } returns emptyList()

        val result = repository.getPlayers()

        assertThat(result).isEqualTo(remotePlayers)
        coVerify { remoteDataSource.getPlayers() }
        coVerify { localDataSource.savePlayers(remotePlayers) }
    }

    @Test
    fun `test get players from local when remote fails`() = runTest {
        val localPlayers = listOf(
            Player(1, "Hero", 100)
        )
        coEvery { remoteDataSource.getPlayers() } throws Exception("Network error")
        coEvery { localDataSource.getPlayers() } returns localPlayers

        val result = repository.getPlayers()

        assertThat(result).isEqualTo(localPlayers)
        coVerify { localDataSource.getPlayers() }
    }
}

// ---- Coroutine test helpers ----
@ExperimentalCoroutinesApi
class TestDispatcherRule : TestWatcher() {
    val testDispatcher = UnconfinedTestDispatcher()

    override fun starting(description: Description) {
        Dispatchers.setMain(testDispatcher)
    }

    override fun finished(description: Description) {
        Dispatchers.resetMain()
    }
}

// ---- Usage in tests ----
class ViewModelTest {
    @get:Rule
    val dispatcherRule = TestDispatcherRule()

    @Test
    fun testCoroutine() = runTest {
        // Test code
    }
}

